Your code likely uses ECB (Electronic Codebook) mode, which is fundamentally broken for most encryption use cases. ECB mode encrypts each block independently with the same key, producing identical ciphertext for identical plaintext blocks. This reveals patterns in your data that attackers can exploit.

**VULNERABLE CODE**:

```javascript
const crypto = require('crypto');

class UserDataEncryption {
  constructor(encryptionKey) {
    // Using a 256-bit key
    this.key = crypto.scryptSync(encryptionKey, 'salt', 32);
  }

  encryptUserData(userData) {
    // VULNERABLE: ECB mode encrypts blocks independently
    const cipher = crypto.createCipheriv('aes-256-ecb', this.key, null);

    let encrypted = cipher.update(JSON.stringify(userData), 'utf8', 'hex');
    encrypted += cipher.final('hex');

    return encrypted;
  }

  decryptUserData(encryptedData) {
    const decipher = crypto.createDecipheriv('aes-256-ecb', this.key, null);

    let decrypted = decipher.update(encryptedData, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return JSON.parse(decrypted);
  }
}

// Usage
const encryption = new UserDataEncryption('my-secret-key');
const user1 = encryption.encryptUserData({ password: 'secret123' });
const user2 = encryption.encryptUserData({ password: 'secret123' });
// user1 === user2 - IDENTICAL CIPHERTEXT!
```

**Attack Demonstration**:
```javascript
// Same plaintext produces same ciphertext
const password1 = encryption.encryptUserData({ password: 'Password1!' });
const password2 = encryption.encryptUserData({ password: 'Password1!' });
console.log(password1 === password2); // true - attackers can identify duplicate passwords!

// Pattern analysis reveals structure in encrypted images/data
// Famous "ECB Penguin" demonstrates visual patterns preserved in encrypted images
```

**Why This Is Dangerous**:
- Identical plaintext blocks produce identical ciphertext blocks, revealing patterns
- Attackers can identify users with the same password by comparing ciphertext
- Block manipulation attacks allow swapping encrypted blocks between records
- No protection against replay attacks or ciphertext tampering
- Adobe's 2013 breach exposed 153 million passwords due to ECB mode

**SECURE VERSION**:

```javascript
const crypto = require('crypto');

class SecureUserDataEncryption {
  constructor(masterKey) {
    // Derive a proper key using PBKDF2 or scrypt
    this.masterKey = crypto.scryptSync(masterKey, 'application-salt-v1', 32);
  }

  encryptUserData(userData) {
    // SECURE: GCM mode provides confidentiality AND authenticity
    const iv = crypto.randomBytes(12); // 96-bit IV for GCM
    const cipher = crypto.createCipheriv('aes-256-gcm', this.masterKey, iv);

    // Add associated data for additional authentication
    const aad = Buffer.from('user-data-encryption-v1');
    cipher.setAAD(aad);

    let encrypted = cipher.update(JSON.stringify(userData), 'utf8', 'hex');
    encrypted += cipher.final('hex');

    // Get the authentication tag
    const authTag = cipher.getAuthTag();

    // Return IV + AuthTag + Ciphertext
    return {
      iv: iv.toString('hex'),
      authTag: authTag.toString('hex'),
      ciphertext: encrypted,
      version: 1
    };
  }

  decryptUserData(encryptedPackage) {
    const iv = Buffer.from(encryptedPackage.iv, 'hex');
    const authTag = Buffer.from(encryptedPackage.authTag, 'hex');

    const decipher = crypto.createDecipheriv('aes-256-gcm', this.masterKey, iv);
    decipher.setAAD(Buffer.from('user-data-encryption-v1'));
    decipher.setAuthTag(authTag);

    let decrypted = decipher.update(encryptedPackage.ciphertext, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return JSON.parse(decrypted);
  }
}

// Usage - same data produces DIFFERENT ciphertext each time
const secureEncryption = new SecureUserDataEncryption('my-secret-key');
const encrypted1 = secureEncryption.encryptUserData({ password: 'secret123' });
const encrypted2 = secureEncryption.encryptUserData({ password: 'secret123' });
// encrypted1.ciphertext !== encrypted2.ciphertext - DIFFERENT every time!
```

**Key Security Controls**:
- **AES-256-GCM mode**: Provides authenticated encryption with associated data (AEAD), ensuring both confidentiality and integrity
- **Random IV per encryption**: Each encryption operation uses a unique 12-byte IV, ensuring identical plaintexts produce different ciphertexts
- **Authentication tag**: Detects any tampering with the ciphertext, preventing bit-flipping and block manipulation attacks
- **Associated data (AAD)**: Binds context to the encryption, preventing ciphertext from being used in different contexts

For production systems handling large files and streaming data, you need a comprehensive encryption architecture that supports key rotation, handles memory efficiently, and provides proper audit logging.

**PRODUCTION PATTERN**:

```javascript
const crypto = require('crypto');
const { Transform } = require('stream');
const fs = require('fs');

class ProductionEncryptionService {
  constructor(config) {
    this.keyStore = new Map(); // In production, use HSM or KMS
    this.currentKeyVersion = config.currentKeyVersion;
    this.algorithm = 'aes-256-gcm';
    this.ivLength = 12;
    this.authTagLength = 16;
    this.logger = config.logger || console;

    // Initialize keys (in production, load from secure key management)
    this.initializeKeys(config.keys);
  }

  initializeKeys(keys) {
    for (const [version, keyMaterial] of Object.entries(keys)) {
      // Derive encryption key using proper KDF
      const derivedKey = crypto.scryptSync(
        keyMaterial,
        `encryption-key-v${version}`,
        32,
        { N: 16384, r: 8, p: 1 }
      );
      this.keyStore.set(parseInt(version), derivedKey);
    }
  }

  // Encrypt data with automatic key versioning
  async encryptData(plaintext, context = {}) {
    const operationId = crypto.randomUUID();
    const startTime = Date.now();

    try {
      const key = this.keyStore.get(this.currentKeyVersion);
      if (!key) {
        throw new Error(`Key version ${this.currentKeyVersion} not found`);
      }

      const iv = crypto.randomBytes(this.ivLength);
      const cipher = crypto.createCipheriv(this.algorithm, key, iv, {
        authTagLength: this.authTagLength
      });

      // Build AAD with context for binding
      const aad = this.buildAAD(context, this.currentKeyVersion);
      cipher.setAAD(aad);

      const encrypted = Buffer.concat([
        cipher.update(Buffer.from(plaintext)),
        cipher.final()
      ]);

      const authTag = cipher.getAuthTag();

      // Create versioned envelope
      const envelope = {
        v: this.currentKeyVersion,
        iv: iv.toString('base64'),
        tag: authTag.toString('base64'),
        ct: encrypted.toString('base64'),
        ctx: this.hashContext(context)
      };

      this.logOperation('encrypt', operationId, startTime, true, context);
      return envelope;

    } catch (error) {
      this.logOperation('encrypt', operationId, startTime, false, context, error);
      throw new EncryptionError('Encryption failed', { cause: error });
    }
  }

  // Decrypt with automatic key version detection
  async decryptData(envelope, context = {}) {
    const operationId = crypto.randomUUID();
    const startTime = Date.now();

    try {
      // Validate envelope structure
      this.validateEnvelope(envelope);

      // Verify context hash matches
      if (envelope.ctx !== this.hashContext(context)) {
        throw new Error('Context mismatch - possible tampering');
      }

      const key = this.keyStore.get(envelope.v);
      if (!key) {
        throw new Error(`Key version ${envelope.v} not available for decryption`);
      }

      const iv = Buffer.from(envelope.iv, 'base64');
      const authTag = Buffer.from(envelope.tag, 'base64');
      const ciphertext = Buffer.from(envelope.ct, 'base64');

      const decipher = crypto.createDecipheriv(this.algorithm, key, iv, {
        authTagLength: this.authTagLength
      });

      const aad = this.buildAAD(context, envelope.v);
      decipher.setAAD(aad);
      decipher.setAuthTag(authTag);

      const decrypted = Buffer.concat([
        decipher.update(ciphertext),
        decipher.final()
      ]);

      this.logOperation('decrypt', operationId, startTime, true, context);
      return decrypted;

    } catch (error) {
      this.logOperation('decrypt', operationId, startTime, false, context, error);

      // Don't leak specifics about authentication failures
      if (error.message.includes('Unsupported state') || 
          error.message.includes('auth')) {
        throw new EncryptionError('Decryption failed - data may be corrupted or tampered');
      }
      throw new EncryptionError('Decryption failed', { cause: error });
    }
  }

  // Streaming encryption for large files
  createEncryptStream(context = {}) {
    const key = this.keyStore.get(this.currentKeyVersion);
    const iv = crypto.randomBytes(this.ivLength);
    const cipher = crypto.createCipheriv(this.algorithm, key, iv, {
      authTagLength: this.authTagLength
    });

    const aad = this.buildAAD(context, this.currentKeyVersion);
    cipher.setAAD(aad);

    let headerWritten = false;
    const keyVersion = this.currentKeyVersion;
    const contextHash = this.hashContext(context);

    const encryptTransform = new Transform({
      transform(chunk, encoding, callback) {
        try {
          // Write header on first chunk
          if (!headerWritten) {
            // Header: version (1 byte) + IV (12 bytes) + context hash (32 bytes)
            const header = Buffer.alloc(45);
            header.writeUInt8(keyVersion, 0);
            iv.copy(header, 1);
            Buffer.from(contextHash, 'hex').copy(header, 13);
            this.push(header);
            headerWritten = true;
          }

          const encrypted = cipher.update(chunk);
          callback(null, encrypted);
        } catch (error) {
          callback(error);
        }
      },
      flush(callback) {
        try {
          const final = cipher.final();
          const authTag = cipher.getAuthTag();
          // Append auth tag at the end
          this.push(final);
          this.push(authTag);
          callback();
        } catch (error) {
          callback(error);
        }
      }
    });

    return encryptTransform;
  }

  // Key rotation - re-encrypt data with new key
  async rotateKey(envelope, context = {}) {
    const plaintext = await this.decryptData(envelope, context);
    return await this.encryptData(plaintext, context);
  }

  // Batch key rotation for migration
  async *batchRotateKeys(envelopes, context = {}) {
    for (const envelope of envelopes) {
      if (envelope.v < this.currentKeyVersion) {
        yield await this.rotateKey(envelope, context);
      } else {
        yield envelope; // Already using current key
      }
    }
  }

  buildAAD(context, keyVersion) {
    return Buffer.from(JSON.stringify({
      app: 'secure-app-v1',
      keyVersion,
      purpose: context.purpose || 'general',
      userId: context.userId || 'system'
    }));
  }

  hashContext(context) {
    return crypto.createHash('sha256')
      .update(JSON.stringify(context))
      .digest('hex');
  }

  validateEnvelope(envelope) {
    const required = ['v', 'iv', 'tag', 'ct', 'ctx'];
    for (const field of required) {
      if (!(field in envelope)) {
        throw new Error(`Missing required field: ${field}`);
      }
    }
    if (typeof envelope.v !== 'number' || envelope.v < 1) {
      throw new Error('Invalid key version');
    }
  }

  logOperation(operation, operationId, startTime, success, context, error = null) {
    const logEntry = {
      timestamp: new Date().toISOString(),
      operationId,
      operation,
      success,
      durationMs: Date.now() - startTime,
      keyVersion: this.currentKeyVersion,
      userId: context.userId || 'unknown',
      purpose: context.purpose || 'unspecified'
    };

    if (error) {
      logEntry.errorType = error.constructor.name;
      // Don't log sensitive error details
    }

    this.logger.info('crypto_operation', logEntry);
  }
}

class EncryptionError extends Error {
  constructor(message, options) {
    super(message, options);
    this.name = 'EncryptionError';
  }
}

// Production usage example
const encryptionService = new ProductionEncryptionService({
  currentKeyVersion: 2,
  keys: {
    1: process.env.ENCRYPTION_KEY_V1,
    2: process.env.ENCRYPTION_KEY_V2
  },
  logger: require('./logger')
});

// Encrypt user data
const encrypted = await encryptionService.encryptData(
  JSON.stringify({ ssn: '123-45-6789', creditCard: '4111111111111111' }),
  { userId: 'user-123', purpose: 'pii-storage' }
);

// Stream encryption for large files
const readStream = fs.createReadStream('large-backup.sql');
const writeStream = fs.createWriteStream('large-backup.sql.enc');
const encryptStream = encryptionService.createEncryptStream({ 
  purpose: 'backup',
  userId: 'system'
});

readStream.pipe(encryptStream).pipe(writeStream);
```

**Defense in Depth Layers**:

1. **Authenticated Encryption (AES-GCM)**: Prevents both eavesdropping and tampering
```javascript
// Authentication tag validates ciphertext integrity
decipher.setAuthTag(authTag); // Throws if tampered
```

2. **Key Versioning**: Enables seamless key rotation without data loss
```javascript
// Old data can still be decrypted during migration
const key = this.keyStore.get(envelope.v); // Get correct key version
```

3. **Context Binding**: Prevents ciphertext from being used in wrong context
```javascript
// AAD binds encryption to specific purpose/user
const aad = this.buildAAD(context, keyVersion);
cipher.setAAD(aad);
```

**Additional Protections**:
- **Memory-safe streaming**: Large files encrypted without loading entirely into memory
- **Audit logging**: All crypto operations logged with operation IDs for forensics
- **Error sanitization**: Crypto errors don't leak implementation details
- **Key derivation**: Uses scrypt with proper parameters for key derivation
- **Envelope format**: Self-describing format enables future algorithm upgrades
- **Batch rotation**: Async generator for memory-efficient bulk re-encryption

Using AES alone is NOT enough - the encryption mode is critical. ECB (Electronic Codebook) mode is the default in many implementations and is fundamentally insecure for most data.

**VULNERABLE CODE**:

```java
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.SecretKeySpec;
import java.util.Base64;

public class InsecureCreditCardEncryption {

    private static final String ALGORITHM = "AES";
    // DANGEROUS: ECB mode is default when not specified!
    private static final String TRANSFORMATION = "AES/ECB/PKCS5Padding";

    private SecretKey secretKey;

    public InsecureCreditCardEncryption(byte[] keyBytes) {
        this.secretKey = new SecretKeySpec(keyBytes, ALGORITHM);
    }

    public String encryptCreditCard(String creditCardNumber) throws Exception {
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        cipher.init(Cipher.ENCRYPT_MODE, secretKey);
        byte[] encryptedBytes = cipher.doFinal(creditCardNumber.getBytes("UTF-8"));
        return Base64.getEncoder().encodeToString(encryptedBytes);
    }

    public String decryptCreditCard(String encryptedData) throws Exception {
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        cipher.init(Cipher.DECRYPT_MODE, secretKey);
        byte[] decryptedBytes = cipher.doFinal(Base64.getDecoder().decode(encryptedData));
        return new String(decryptedBytes, "UTF-8");
    }
}
```

**Pattern Analysis Attack**:
```text
# If two users have the same credit card prefix (e.g., 4111-1111):
User A card: 4111111111111111 -> encrypts to: abc123xyz789...
User B card: 4111111199999999 -> encrypts to: abc123xyz456...

# First block (4111-1111) produces IDENTICAL ciphertext!
# Attacker can identify cards from same issuer/BIN range
# With enough samples, can deduce card number patterns
```

**Why This Is Dangerous**:
- ECB mode encrypts identical 16-byte blocks to identical ciphertext
- Credit card numbers share common prefixes (BIN numbers)
- Attackers can perform frequency analysis to identify patterns
- The famous "ECB penguin" demonstrates this visually - encrypted images retain their shape
- No protection against block manipulation or replay attacks

**SECURE VERSION**:

```java
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;
import java.util.Arrays;
import java.util.Base64;

public class SecureCreditCardEncryption {

    private static final String ALGORITHM = "AES";
    // SECURE: GCM mode provides confidentiality AND authenticity
    private static final String TRANSFORMATION = "AES/GCM/NoPadding";
    private static final int GCM_IV_LENGTH = 12; // 96 bits recommended for GCM
    private static final int GCM_TAG_LENGTH = 128; // Authentication tag size

    private final SecretKey secretKey;
    private final SecureRandom secureRandom;

    public SecureCreditCardEncryption(byte[] keyBytes) {
        if (keyBytes.length != 32) {
            throw new IllegalArgumentException("Key must be 256 bits (32 bytes)");
        }
        this.secretKey = new SecretKeySpec(keyBytes, ALGORITHM);
        this.secureRandom = new SecureRandom();
    }

    public String encryptCreditCard(String creditCardNumber) throws Exception {
        // Generate unique IV for each encryption
        byte[] iv = new byte[GCM_IV_LENGTH];
        secureRandom.nextBytes(iv);

        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        cipher.init(Cipher.ENCRYPT_MODE, secretKey, gcmSpec);

        byte[] encryptedBytes = cipher.doFinal(creditCardNumber.getBytes("UTF-8"));

        // Prepend IV to ciphertext for decryption
        byte[] combined = new byte[iv.length + encryptedBytes.length];
        System.arraycopy(iv, 0, combined, 0, iv.length);
        System.arraycopy(encryptedBytes, 0, combined, iv.length, encryptedBytes.length);

        return Base64.getEncoder().encodeToString(combined);
    }

    public String decryptCreditCard(String encryptedData) throws Exception {
        byte[] combined = Base64.getDecoder().decode(encryptedData);

        // Extract IV from beginning
        byte[] iv = Arrays.copyOfRange(combined, 0, GCM_IV_LENGTH);
        byte[] ciphertext = Arrays.copyOfRange(combined, GCM_IV_LENGTH, combined.length);

        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        cipher.init(Cipher.DECRYPT_MODE, secretKey, gcmSpec);

        byte[] decryptedBytes = cipher.doFinal(ciphertext);
        return new String(decryptedBytes, "UTF-8");
    }
}
```

**Key Security Controls**:
- **AES-GCM mode**: Provides authenticated encryption - protects confidentiality AND integrity
- **Unique IV per encryption**: Each encryption produces different ciphertext even for identical plaintext
- **128-bit authentication tag**: Detects any tampering with ciphertext
- **256-bit key enforcement**: Maximum AES security level

Excellent question! This is a common challenge. You need deterministic encryption for searchability but must avoid ECB's weaknesses. The solution is a layered approach using blind indexing or HMAC-based search tokens.

**PRODUCTION PATTERN**:

```java
import javax.crypto.Cipher;
import javax.crypto.Mac;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;
import java.sql.Connection;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.util.Arrays;
import java.util.Base64;
import java.util.logging.Logger;

public class ProductionCryptoService {

    private static final Logger logger = Logger.getLogger(ProductionCryptoService.class.getName());

    private static final String AES_GCM = "AES/GCM/NoPadding";
    private static final String HMAC_ALGORITHM = "HmacSHA256";
    private static final int GCM_IV_LENGTH = 12;
    private static final int GCM_TAG_LENGTH = 128;

    // Separate keys for different purposes (key separation principle)
    private final SecretKey encryptionKey;      // For AES-GCM encryption
    private final SecretKey blindIndexKey;      // For searchable HMAC tokens
    private final SecureRandom secureRandom;

    public ProductionCryptoService(byte[] encKeyBytes, byte[] indexKeyBytes) {
        validateKeyLength(encKeyBytes, "Encryption");
        validateKeyLength(indexKeyBytes, "Blind index");

        this.encryptionKey = new SecretKeySpec(encKeyBytes, "AES");
        this.blindIndexKey = new SecretKeySpec(indexKeyBytes, "HmacSHA256");
        this.secureRandom = new SecureRandom();
    }

    private void validateKeyLength(byte[] key, String keyName) {
        if (key == null || key.length != 32) {
            throw new IllegalArgumentException(keyName + " key must be 256 bits");
        }
    }

    /**
     * Creates a blind index for searchable encryption.
     * Same input always produces same output (deterministic)
     * but HMAC prevents pattern analysis attacks.
     */
    public String createBlindIndex(String sensitiveValue) throws Exception {
        Mac hmac = Mac.getInstance(HMAC_ALGORITHM);
        hmac.init(blindIndexKey);

        // Normalize input to prevent case-sensitivity issues
        String normalized = sensitiveValue.toLowerCase().trim();
        byte[] hash = hmac.doFinal(normalized.getBytes("UTF-8"));

        // Truncate to reduce storage while maintaining uniqueness
        // 16 bytes = 128 bits, sufficient for collision resistance
        byte[] truncated = Arrays.copyOf(hash, 16);
        return Base64.getEncoder().encodeToString(truncated);
    }

    /**
     * Encrypts sensitive data with AES-GCM (random IV each time)
     */
    public String encrypt(String plaintext) throws Exception {
        byte[] iv = new byte[GCM_IV_LENGTH];
        secureRandom.nextBytes(iv);

        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        Cipher cipher = Cipher.getInstance(AES_GCM);
        cipher.init(Cipher.ENCRYPT_MODE, encryptionKey, gcmSpec);

        byte[] ciphertext = cipher.doFinal(plaintext.getBytes("UTF-8"));

        // Format: IV || ciphertext || auth_tag (GCM includes tag automatically)
        byte[] combined = new byte[iv.length + ciphertext.length];
        System.arraycopy(iv, 0, combined, 0, iv.length);
        System.arraycopy(ciphertext, 0, combined, iv.length, ciphertext.length);

        return Base64.getEncoder().encodeToString(combined);
    }

    /**
     * Decrypts AES-GCM encrypted data
     */
    public String decrypt(String encryptedData) throws Exception {
        byte[] combined = Base64.getDecoder().decode(encryptedData);

        if (combined.length < GCM_IV_LENGTH + 16) { // Minimum: IV + tag
            throw new SecurityException("Invalid ciphertext length");
        }

        byte[] iv = Arrays.copyOfRange(combined, 0, GCM_IV_LENGTH);
        byte[] ciphertext = Arrays.copyOfRange(combined, GCM_IV_LENGTH, combined.length);

        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        Cipher cipher = Cipher.getInstance(AES_GCM);
        cipher.init(Cipher.DECRYPT_MODE, encryptionKey, gcmSpec);

        return new String(cipher.doFinal(ciphertext), "UTF-8");
    }

    /**
     * Production database storage with blind indexing
     */
    public void storeCreditCard(Connection conn, String customerId, 
                                 String cardNumber) throws Exception {
        // Create searchable blind index
        String blindIndex = createBlindIndex(cardNumber);
        // Encrypt actual card number with AES-GCM
        String encryptedCard = encrypt(cardNumber);

        String sql = "INSERT INTO credit_cards (customer_id, card_blind_index, " +
                     "encrypted_card, created_at) VALUES (?, ?, ?, NOW())";

        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, customerId);
            stmt.setString(2, blindIndex);    // Searchable, deterministic
            stmt.setString(3, encryptedCard); // Encrypted, non-deterministic
            stmt.executeUpdate();

            logger.info(String.format("Stored encrypted card for customer: %s", 
                        customerId.substring(0, 4) + "****"));
        }
    }

    /**
     * Search by card number without exposing plaintext
     */
    public String findCardByNumber(Connection conn, String cardNumber) throws Exception {
        String blindIndex = createBlindIndex(cardNumber);

        String sql = "SELECT encrypted_card FROM credit_cards WHERE card_blind_index = ?";

        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, blindIndex);

            try (ResultSet rs = stmt.executeQuery()) {
                if (rs.next()) {
                    return decrypt(rs.getString("encrypted_card"));
                }
            }
        }
        return null;
    }
}
```

**Defense in Depth Layers**:

1. **Key Separation**:
```java
// Never use same key for different purposes
private final SecretKey encryptionKey;  // Only for AES-GCM
private final SecretKey blindIndexKey;  // Only for HMAC blind indexes
// If one key is compromised, the other remains secure
```

2. **Secure Key Management with HSM/Vault**:
```java
import com.hashicorp.vault.VaultClient;

public class KeyManagementService {
    private final VaultClient vault;

    public SecretKey getEncryptionKey() throws Exception {
        // Keys never exist in plaintext on application servers
        String keyPath = "secret/data/encryption/credit-cards";
        Map<String, String> secrets = vault.read(keyPath).getData();
        return new SecretKeySpec(
            Base64.getDecoder().decode(secrets.get("key")), 
            "AES"
        );
    }

    // Automatic key rotation
    public void rotateKeys() throws Exception {
        KeyGenerator keyGen = KeyGenerator.getInstance("AES");
        keyGen.init(256, new SecureRandom());
        SecretKey newKey = keyGen.generateKey();

        vault.write("secret/data/encryption/credit-cards", 
            Map.of("key", Base64.getEncoder().encodeToString(newKey.getEncoded())));

        logger.info("Encryption key rotated successfully");
    }
}
```

3. **Audit Logging and Monitoring**:
```java
import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.MeterRegistry;

public class AuditedCryptoService extends ProductionCryptoService {

    private final Counter encryptionCounter;
    private final Counter decryptionCounter;
    private final Counter failureCounter;

    public AuditedCryptoService(byte[] encKey, byte[] indexKey, 
                                 MeterRegistry metrics) {
        super(encKey, indexKey);
        this.encryptionCounter = metrics.counter("crypto.encrypt.count");
        this.decryptionCounter = metrics.counter("crypto.decrypt.count");
        this.failureCounter = metrics.counter("crypto.failures.count");
    }

    @Override
    public String decrypt(String encryptedData) throws Exception {
        try {
            String result = super.decrypt(encryptedData);
            decryptionCounter.increment();

            // Log access for compliance (PCI-DSS requirement)
            AuditLogger.log(AuditEvent.builder()
                .action("DECRYPT_CARD")
                .userId(SecurityContext.getCurrentUser())
                .resourceType("CREDIT_CARD")
                .timestamp(Instant.now())
                .sourceIp(RequestContext.getClientIp())
                .build());

            return result;
        } catch (Exception e) {
            failureCounter.increment();
            logger.severe("Decryption failure - potential tampering detected");
            // Alert security team for GCM authentication failures
            if (e.getMessage().contains("Tag mismatch")) {
                SecurityAlerts.sendCritical("Ciphertext tampering detected");
            }
            throw e;
        }
    }
}
```

**Additional Protections**:
- **Memory protection**: Clear sensitive data from memory after use using `Arrays.fill(sensitiveBytes, (byte) 0)`
- **Rate limiting**: Limit decryption operations to prevent bulk extraction
- **Data masking**: Only return last 4 digits to UI: `"****-****-****-" + cardNumber.substring(12)`
- **PCI-DSS compliance**: Store encrypted cards in separate database segment with restricted access
- **Key rotation**: Implement envelope encryption to allow key rotation without re-encrypting all data

