**PRODUCTION PATTERN**:

```go
package main

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"crypto/sha256"
	"encoding/binary"
	"errors"
	"fmt"
	"io"
	"log"
	"os"
	"time"

	"golang.org/x/crypto/argon2"
	"golang.org/x/crypto/hkdf"
)

const (
	// Chunk size for streaming encryption (64KB)
	ChunkSize = 64 * 1024
	// Salt size for key derivation
	SaltSize = 32
	// Nonce size for AES-GCM
	NonceSize = 12
	// Key size for AES-256
	KeySize = 32
	// Argon2 parameters (OWASP recommended)
	Argon2Time    = 3
	Argon2Memory  = 64 * 1024
	Argon2Threads = 4
)

// EncryptionMetadata stores encryption parameters
type EncryptionMetadata struct {
	Version     uint8
	Algorithm   string
	KeyID       string
	CreatedAt   time.Time
	ChunkSize   int
}

// SecureEncryptor handles production encryption with streaming support
type SecureEncryptor struct {
	masterKey []byte
	keyID     string
	logger    *log.Logger
}

// NewSecureEncryptor creates encryptor with derived key from password
func NewSecureEncryptor(password string, salt []byte, keyID string, logger *log.Logger) (*SecureEncryptor, error) {
	if len(salt) < SaltSize {
		return nil, errors.New("salt must be at least 32 bytes")
	}
	if len(password) < 12 {
		return nil, errors.New("password must be at least 12 characters")
	}

	// Derive key using Argon2id (memory-hard, resistant to GPU attacks)
	key := argon2.IDKey(
		[]byte(password),
		salt,
		Argon2Time,
		Argon2Memory,
		Argon2Threads,
		KeySize,
	)

	logger.Printf("[AUDIT] Encryption key derived for keyID=%s", keyID)

	return &SecureEncryptor{
		masterKey: key,
		keyID:     keyID,
		logger:    logger,
	}, nil
}

// DeriveChunkKey derives unique key for each chunk using HKDF
func (e *SecureEncryptor) DeriveChunkKey(chunkIndex uint64) ([]byte, error) {
	info := make([]byte, 8)
	binary.BigEndian.PutUint64(info, chunkIndex)

	hkdfReader := hkdf.New(sha256.New, e.masterKey, nil, info)
	chunkKey := make([]byte, KeySize)
	if _, err := io.ReadFull(hkdfReader, chunkKey); err != nil {
		return nil, fmt.Errorf("failed to derive chunk key: %w", err)
	}
	return chunkKey, nil
}

// EncryptStream encrypts data from reader to writer using streaming AES-GCM
func (e *SecureEncryptor) EncryptStream(reader io.Reader, writer io.Writer) error {
	startTime := time.Now()
	var totalBytes int64
	var chunkCount uint64

	// Write file header with version and salt
	salt := make([]byte, SaltSize)
	if _, err := rand.Read(salt); err != nil {
		return fmt.Errorf("failed to generate salt: %w", err)
	}

	// Header format: [version:1][salt:32]
	header := append([]byte{0x01}, salt...)
	if _, err := writer.Write(header); err != nil {
		return fmt.Errorf("failed to write header: %w", err)
	}

	buffer := make([]byte, ChunkSize)

	for {
		n, err := reader.Read(buffer)
		if n > 0 {
			// Derive unique key for this chunk
			chunkKey, keyErr := e.DeriveChunkKey(chunkCount)
			if keyErr != nil {
				return keyErr
			}

			block, blockErr := aes.NewCipher(chunkKey)
			if blockErr != nil {
				return fmt.Errorf("failed to create cipher: %w", blockErr)
			}

			aesGCM, gcmErr := cipher.NewGCM(block)
			if gcmErr != nil {
				return fmt.Errorf("failed to create GCM: %w", gcmErr)
			}

			// Generate random nonce for each chunk
			nonce := make([]byte, NonceSize)
			if _, randErr := rand.Read(nonce); randErr != nil {
				return fmt.Errorf("failed to generate nonce: %w", randErr)
			}

			// Encrypt chunk with authenticated encryption
			ciphertext := aesGCM.Seal(nil, nonce, buffer[:n], nil)

			// Write chunk format: [nonce:12][length:4][ciphertext+tag]
			chunkHeader := make([]byte, NonceSize+4)
			copy(chunkHeader[:NonceSize], nonce)
			binary.BigEndian.PutUint32(chunkHeader[NonceSize:], uint32(len(ciphertext)))

			if _, writeErr := writer.Write(chunkHeader); writeErr != nil {
				return fmt.Errorf("failed to write chunk header: %w", writeErr)
			}
			if _, writeErr := writer.Write(ciphertext); writeErr != nil {
				return fmt.Errorf("failed to write ciphertext: %w", writeErr)
			}

			totalBytes += int64(n)
			chunkCount++

			// Clear sensitive data from memory
			for i := range chunkKey {
				chunkKey[i] = 0
			}
		}

		if err == io.EOF {
			break
		}
		if err != nil {
			return fmt.Errorf("read error: %w", err)
		}
	}

	e.logger.Printf("[AUDIT] Encryption complete: keyID=%s bytes=%d chunks=%d duration=%v",
		e.keyID, totalBytes, chunkCount, time.Since(startTime))

	return nil
}

// DecryptStream decrypts data from reader to writer
func (e *SecureEncryptor) DecryptStream(reader io.Reader, writer io.Writer) error {
	startTime := time.Now()
	var totalBytes int64
	var chunkCount uint64

	// Read and validate header
	header := make([]byte, 1+SaltSize)
	if _, err := io.ReadFull(reader, header); err != nil {
		return fmt.Errorf("failed to read header: %w", err)
	}

	if header[0] != 0x01 {
		return errors.New("unsupported encryption version")
	}

	chunkHeader := make([]byte, NonceSize+4)

	for {
		_, err := io.ReadFull(reader, chunkHeader)
		if err == io.EOF {
			break
		}
		if err != nil {
			return fmt.Errorf("failed to read chunk header: %w", err)
		}

		nonce := chunkHeader[:NonceSize]
		ciphertextLen := binary.BigEndian.Uint32(chunkHeader[NonceSize:])

		// Validate chunk size to prevent memory exhaustion
		if ciphertextLen > ChunkSize+16 { // 16 bytes for GCM tag
			return errors.New("invalid chunk size detected")
		}

		ciphertext := make([]byte, ciphertextLen)
		if _, err := io.ReadFull(reader, ciphertext); err != nil {
			return fmt.Errorf("failed to read ciphertext: %w", err)
		}

		// Derive chunk key
		chunkKey, keyErr := e.DeriveChunkKey(chunkCount)
		if keyErr != nil {
			return keyErr
		}

		block, blockErr := aes.NewCipher(chunkKey)
		if blockErr != nil {
			return fmt.Errorf("failed to create cipher: %w", blockErr)
		}

		aesGCM, gcmErr := cipher.NewGCM(block)
		if gcmErr != nil {
			return fmt.Errorf("failed to create GCM: %w", gcmErr)
		}

		// Decrypt and verify authentication tag
		plaintext, decErr := aesGCM.Open(nil, nonce, ciphertext, nil)
		if decErr != nil {
			e.logger.Printf("[SECURITY] Decryption failed at chunk %d - possible tampering", chunkCount)
			return fmt.Errorf("authentication failed at chunk %d: %w", chunkCount, decErr)
		}

		if _, writeErr := writer.Write(plaintext); writeErr != nil {
			return fmt.Errorf("failed to write plaintext: %w", writeErr)
		}

		totalBytes += int64(len(plaintext))
		chunkCount++

		// Clear sensitive data
		for i := range chunkKey {
			chunkKey[i] = 0
		}
	}

	e.logger.Printf("[AUDIT] Decryption complete: keyID=%s bytes=%d chunks=%d duration=%v",
		e.keyID, totalBytes, chunkCount, time.Since(startTime))

	return nil
}

// SecureKeyStorage provides key management with envelope encryption
type SecureKeyStorage struct {
	kekProvider func() ([]byte, error) // Key Encryption Key from HSM/KMS
	logger      *log.Logger
}

// WrapKey encrypts a data encryption key with the KEK
func (s *SecureKeyStorage) WrapKey(dek []byte) ([]byte, error) {
	kek, err := s.kekProvider()
	if err != nil {
		return nil, fmt.Errorf("failed to get KEK: %w", err)
	}
	defer func() {
		for i := range kek {
			kek[i] = 0
		}
	}()

	block, err := aes.NewCipher(kek)
	if err != nil {
		return nil, err
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return nil, err
	}

	nonce := make([]byte, aesGCM.NonceSize())
	if _, err := rand.Read(nonce); err != nil {
		return nil, err
	}

	wrappedKey := aesGCM.Seal(nonce, nonce, dek, nil)
	s.logger.Printf("[AUDIT] DEK wrapped successfully")
	return wrappedKey, nil
}

func main() {
	logger := log.New(os.Stdout, "[CRYPTO] ", log.LstdFlags|log.Lshortfile)

	// Generate random salt (store this with the encrypted data)
	salt := make([]byte, SaltSize)
	if _, err := rand.Read(salt); err != nil {
		logger.Fatalf("Failed to generate salt: %v", err)
	}

	// Create encryptor with strong password
	encryptor, err := NewSecureEncryptor(
		"MySecureP@ssw0rd2024!",
		salt,
		"user-data-key-001",
		logger,
	)
	if err != nil {
		logger.Fatalf("Failed to create encryptor: %v", err)
	}

	// Example: Encrypt a file
	inputFile, _ := os.Open("sensitive_data.txt")
	defer inputFile.Close()

	outputFile, _ := os.Create("sensitive_data.enc")
	defer outputFile.Close()

	if err := encryptor.EncryptStream(inputFile, outputFile); err != nil {
		logger.Fatalf("Encryption failed: %v", err)
	}

	logger.Println("File encrypted successfully with AES-256-GCM")
}
```

