**SECURE VERSION**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Configuration;

public class SecureEncryption
{
    private readonly byte[] _key;

    public SecureEncryption(IConfiguration configuration)
    {
        // Key from secure configuration (Azure Key Vault, AWS Secrets Manager, etc.)
        string keyBase64 = configuration["Encryption:AesKey"]
            ?? throw new InvalidOperationException("Encryption key not configured");
        _key = Convert.FromBase64String(keyBase64);

        if (_key.Length != 32) // AES-256
            throw new ArgumentException("Key must be 256 bits (32 bytes)");
    }

    public byte[] Encrypt(string plaintext)
    {
        if (string.IsNullOrEmpty(plaintext))
            throw new ArgumentNullException(nameof(plaintext));

        using (Aes aes = Aes.Create())
        {
            aes.Key = _key;
            aes.Mode = CipherMode.CBC;  // SECURE: CBC mode with random IV
            aes.Padding = PaddingMode.PKCS7;
            aes.GenerateIV();  // Random IV for each encryption

            using (MemoryStream ms = new MemoryStream())
            {
                // Prepend IV to ciphertext (IV is not secret)
                ms.Write(aes.IV, 0, aes.IV.Length);

                using (CryptoStream cs = new CryptoStream(ms, aes.CreateEncryptor(), CryptoStreamMode.Write))
                {
                    byte[] plaintextBytes = Encoding.UTF8.GetBytes(plaintext);
                    cs.Write(plaintextBytes, 0, plaintextBytes.Length);
                    cs.FlushFinalBlock();
                }

                return ms.ToArray();
            }
        }
    }

    public string Decrypt(byte[] ciphertext)
    {
        if (ciphertext == null || ciphertext.Length < 17) // IV (16) + at least 1 byte
            throw new ArgumentException("Invalid ciphertext");

        using (Aes aes = Aes.Create())
        {
            aes.Key = _key;
            aes.Mode = CipherMode.CBC;
            aes.Padding = PaddingMode.PKCS7;

            // Extract IV from beginning of ciphertext
            byte[] iv = new byte[16];
            Array.Copy(ciphertext, 0, iv, 0, 16);
            aes.IV = iv;

            using (MemoryStream ms = new MemoryStream(ciphertext, 16, ciphertext.Length - 16))
            using (CryptoStream cs = new CryptoStream(ms, aes.CreateDecryptor(), CryptoStreamMode.Read))
            using (StreamReader reader = new StreamReader(cs, Encoding.UTF8))
            {
                return reader.ReadToEnd();
            }
        }
    }
}
```

**Key Security Controls**:
- **CBC mode with random IV**: Each encryption produces unique ciphertext even for identical plaintext, preventing pattern analysis
- **AES-256**: Stronger 256-bit key vs 128-bit provides better security margin
- **IV prepended to ciphertext**: IV is stored with ciphertext for decryption, doesn't need to be secret
- **External key management**: Key loaded from secure configuration, not hardcoded

Great questions! CBC mode provides confidentiality but not integrity. For production systems, you need authenticated encryption (AEAD) which provides both, plus a robust key rotation strategy.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Configuration;
using Azure.Security.KeyVault.Keys.Cryptography;
using Azure.Identity;

namespace MyApp.Security
{
    public class ProductionEncryptionService : IDisposable
    {
        private readonly ILogger<ProductionEncryptionService> _logger;
        private readonly IConfiguration _configuration;
        private readonly Dictionary<string, byte[]> _keyCache;
        private readonly object _keyLock = new object();
        private bool _disposed;

        // Key version header format: [KeyVersion(4)][Nonce(12)][Ciphertext][Tag(16)]
        private const int KEY_VERSION_SIZE = 4;
        private const int NONCE_SIZE = 12;
        private const int TAG_SIZE = 16;

        public ProductionEncryptionService(
            ILogger<ProductionEncryptionService> logger,
            IConfiguration configuration)
        {
            _logger = logger;
            _configuration = configuration;
            _keyCache = new Dictionary<string, byte[]>();
        }

        /// <summary>
        /// Encrypts data using AES-256-GCM (authenticated encryption)
        /// </summary>
        public byte[] Encrypt(string plaintext, string keyVersion = null)
        {
            if (string.IsNullOrEmpty(plaintext))
                throw new ArgumentNullException(nameof(plaintext));

            keyVersion ??= GetCurrentKeyVersion();
            byte[] key = GetKey(keyVersion);

            byte[] nonce = new byte[NONCE_SIZE];
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(nonce);
            }

            byte[] plaintextBytes = Encoding.UTF8.GetBytes(plaintext);
            byte[] ciphertext = new byte[plaintextBytes.Length];
            byte[] tag = new byte[TAG_SIZE];

            using (AesGcm aesGcm = new AesGcm(key, TAG_SIZE))
            {
                aesGcm.Encrypt(nonce, plaintextBytes, ciphertext, tag);
            }

            // Build output: [KeyVersion][Nonce][Ciphertext][Tag]
            byte[] keyVersionBytes = BitConverter.GetBytes(int.Parse(keyVersion));
            byte[] result = new byte[KEY_VERSION_SIZE + NONCE_SIZE + ciphertext.Length + TAG_SIZE];

            Buffer.BlockCopy(keyVersionBytes, 0, result, 0, KEY_VERSION_SIZE);
            Buffer.BlockCopy(nonce, 0, result, KEY_VERSION_SIZE, NONCE_SIZE);
            Buffer.BlockCopy(ciphertext, 0, result, KEY_VERSION_SIZE + NONCE_SIZE, ciphertext.Length);
            Buffer.BlockCopy(tag, 0, result, KEY_VERSION_SIZE + NONCE_SIZE + ciphertext.Length, TAG_SIZE);

            _logger.LogDebug("Data encrypted with key version {KeyVersion}", keyVersion);

            // Clear sensitive data from memory
            CryptographicOperations.ZeroMemory(plaintextBytes);

            return result;
        }

        /// <summary>
        /// Decrypts and authenticates data using AES-256-GCM
        /// </summary>
        public string Decrypt(byte[] encryptedData)
        {
            if (encryptedData == null || encryptedData.Length < KEY_VERSION_SIZE + NONCE_SIZE + TAG_SIZE + 1)
                throw new ArgumentException("Invalid encrypted data format");

            // Extract key version
            byte[] keyVersionBytes = new byte[KEY_VERSION_SIZE];
            Buffer.BlockCopy(encryptedData, 0, keyVersionBytes, 0, KEY_VERSION_SIZE);
            string keyVersion = BitConverter.ToInt32(keyVersionBytes, 0).ToString();

            // Extract nonce
            byte[] nonce = new byte[NONCE_SIZE];
            Buffer.BlockCopy(encryptedData, KEY_VERSION_SIZE, nonce, 0, NONCE_SIZE);

            // Extract ciphertext and tag
            int ciphertextLength = encryptedData.Length - KEY_VERSION_SIZE - NONCE_SIZE - TAG_SIZE;
            byte[] ciphertext = new byte[ciphertextLength];
            byte[] tag = new byte[TAG_SIZE];

            Buffer.BlockCopy(encryptedData, KEY_VERSION_SIZE + NONCE_SIZE, ciphertext, 0, ciphertextLength);
            Buffer.BlockCopy(encryptedData, KEY_VERSION_SIZE + NONCE_SIZE + ciphertextLength, tag, 0, TAG_SIZE);

            byte[] key = GetKey(keyVersion);
            byte[] plaintextBytes = new byte[ciphertextLength];

            try
            {
                using (AesGcm aesGcm = new AesGcm(key, TAG_SIZE))
                {
                    aesGcm.Decrypt(nonce, ciphertext, tag, plaintextBytes);
                }
            }
            catch (AuthenticationTagMismatchException)
            {
                _logger.LogWarning("Authentication tag mismatch - potential tampering detected");
                throw new CryptographicException("Data integrity verification failed - possible tampering");
            }

            string result = Encoding.UTF8.GetString(plaintextBytes);

            // Clear sensitive data
            CryptographicOperations.ZeroMemory(plaintextBytes);

            // Log successful decryption with old key version for rotation monitoring
            if (keyVersion != GetCurrentKeyVersion())
            {
                _logger.LogInformation(
                    "Decrypted data using old key version {OldVersion}, current is {CurrentVersion}",
                    keyVersion, GetCurrentKeyVersion());
            }

            return result;
        }

        /// <summary>
        /// Re-encrypts data with the current key version (for key rotation)
        /// </summary>
        public byte[] ReEncrypt(byte[] encryptedData)
        {
            string plaintext = Decrypt(encryptedData);
            byte[] result = Encrypt(plaintext, GetCurrentKeyVersion());

            // Clear plaintext from memory
            CryptographicOperations.ZeroMemory(Encoding.UTF8.GetBytes(plaintext));

            return result;
        }

        private string GetCurrentKeyVersion()
        {
            return _configuration["Encryption:CurrentKeyVersion"]
                ?? throw new InvalidOperationException("Current key version not configured");
        }

        private byte[] GetKey(string version)
        {
            lock (_keyLock)
            {
                if (_keyCache.TryGetValue(version, out byte[] cachedKey))
                    return cachedKey;

                // Load from Azure Key Vault (or AWS Secrets Manager, HashiCorp Vault)
                string keyVaultUrl = _configuration["KeyVault:Url"];
                string keyName = $"encryption-key-v{version}";

                var client = new CryptographyClient(
                    new Uri($"{keyVaultUrl}/keys/{keyName}"),
                    new DefaultAzureCredential());

                // For this example, we fetch the key material
                // In production, consider using Key Vault's encrypt/decrypt operations directly
                string keyBase64 = _configuration[$"Encryption:Keys:{version}"]
                    ?? throw new InvalidOperationException($"Key version {version} not found");

                byte[] key = Convert.FromBase64String(keyBase64);

                if (key.Length != 32)
                    throw new InvalidOperationException("Key must be 256 bits");

                _keyCache[version] = key;

                _logger.LogInformation("Loaded encryption key version {Version}", version);

                return key;
            }
        }

        public void Dispose()
        {
            if (_disposed) return;

            lock (_keyLock)
            {
                foreach (var key in _keyCache.Values)
                {
                    CryptographicOperations.ZeroMemory(key);
                }
                _keyCache.Clear();
            }

            _disposed = true;
        }
    }

    // Background service for key rotation
    public class KeyRotationService
    {
        private readonly ProductionEncryptionService _encryptionService;
        private readonly IDataRepository _dataRepository;
        private readonly ILogger<KeyRotationService> _logger;

        public KeyRotationService(
            ProductionEncryptionService encryptionService,
            IDataRepository dataRepository,
