            _dataRepository = dataRepository;
            _logger = logger;
        }

        public async Task RotateEncryptedDataAsync(int batchSize = 1000)
        {
            _logger.LogInformation("Starting key rotation process");
            int totalRotated = 0;

            try
            {
                while (true)
                {
                    var records = await _dataRepository.GetRecordsWithOldKeyAsync(batchSize);
                    if (!records.Any()) break;

                    foreach (var record in records)
                    {
                        try
                        {
                            byte[] reEncrypted = _encryptionService.ReEncrypt(record.EncryptedData);
                            await _dataRepository.UpdateEncryptedDataAsync(record.Id, reEncrypted);
                            totalRotated++;
                        }
                        catch (Exception ex)
                        {
                            _logger.LogError(ex, "Failed to rotate record {RecordId}", record.Id);
                        }
                    }

                    _logger.LogInformation("Rotated {Count} records so far", totalRotated);
                }

                _logger.LogInformation("Key rotation complete. Total records rotated: {Total}", totalRotated);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Key rotation process failed after rotating {Count} records", totalRotated);
                throw;
            }
        }
    }
