const crypto = require('crypto');
const fs = require('fs');
const { pipeline } = require('stream/promises');
const { Transform } = require('stream');

class ProductionCryptoService {
  constructor(config) {
    this.keyStore = new Map(); // In production, use HSM or KMS
    this.currentKeyVersion = null;
    this.algorithm = 'aes-256-gcm';
    this.ivLength = 12;
    this.tagLength = 16;
    this.logger = config.logger || console;
  }

  // Key management with versioning for rotation
  async addKey(keyVersion, keyMaterial) {
    if (keyMaterial.length !== 32) {
      throw new Error('Key must be 256 bits (32 bytes)');
    }
    this.keyStore.set(keyVersion, {
      key: keyMaterial,
      createdAt: new Date(),
      status: 'active'
    });
    this.currentKeyVersion = keyVersion;
    this.logger.info(`Key version ${keyVersion} added`, {
      timestamp: new Date().toISOString(),
      event: 'key_added'
    });
  }

  // Rotate to new key while keeping old for decryption
  async rotateKey(newKeyVersion, newKeyMaterial) {
    const oldVersion = this.currentKeyVersion;

    // Mark old key as decrypt-only
    if (this.keyStore.has(oldVersion)) {
      this.keyStore.get(oldVersion).status = 'decrypt-only';
    }

    await this.addKey(newKeyVersion, newKeyMaterial);

    this.logger.info('Key rotation completed', {
      oldVersion,
      newVersion: newKeyVersion,
      timestamp: new Date().toISOString()
    });

    return { oldVersion, newVersion: newKeyVersion };
  }

  // Encrypt with key version embedded for rotation support
  encrypt(plaintext, associatedData = '') {
    if (!this.currentKeyVersion) {
      throw new Error('No encryption key configured');
    }

    const keyData = this.keyStore.get(this.currentKeyVersion);
    if (keyData.status !== 'active') {
      throw new Error('Current key is not active for encryption');
    }

    const iv = crypto.randomBytes(this.ivLength);
    const cipher = crypto.createCipheriv(this.algorithm, keyData.key, iv, {
      authTagLength: this.tagLength
    });

    // Associated data provides context binding (not encrypted but authenticated)
    if (associatedData) {
      cipher.setAAD(Buffer.from(associatedData, 'utf8'));
    }

    const encrypted = Buffer.concat([
      cipher.update(Buffer.from(plaintext, 'utf8')),
      cipher.final()
    ]);

    const authTag = cipher.getAuthTag();

    // Format: version(4) + iv(12) + tag(16) + ciphertext
    const versionBuffer = Buffer.alloc(4);
    versionBuffer.writeUInt32BE(this.currentKeyVersion);

    const result = Buffer.concat([versionBuffer, iv, authTag, encrypted]);

    this.logger.debug('Encryption completed', {
      keyVersion: this.currentKeyVersion,
      dataLength: plaintext.length,
      hasAAD: !!associatedData
    });

    return result.toString('base64');
  }

  // Decrypt with automatic key version detection
  decrypt(encryptedBase64, associatedData = '') {
    const data = Buffer.from(encryptedBase64, 'base64');

    if (data.length < 4 + this.ivLength + this.tagLength) {
      throw new Error('Invalid ciphertext: too short');
    }

    // Extract components
    const keyVersion = data.readUInt32BE(0);
    const iv = data.subarray(4, 4 + this.ivLength);
    const authTag = data.subarray(4 + this.ivLength, 4 + this.ivLength + this.tagLength);
    const ciphertext = data.subarray(4 + this.ivLength + this.tagLength);

    const keyData = this.keyStore.get(keyVersion);
    if (!keyData) {
      throw new Error(`Key version ${keyVersion} not found`);
    }

    const decipher = crypto.createDecipheriv(this.algorithm, keyData.key, iv, {
      authTagLength: this.tagLength
    });

    decipher.setAuthTag(authTag);

    if (associatedData) {
      decipher.setAAD(Buffer.from(associatedData, 'utf8'));
    }

    try {
      const decrypted = Buffer.concat([
        decipher.update(ciphertext),
        decipher.final()
      ]);

      this.logger.debug('Decryption completed', {
        keyVersion,
        dataLength: decrypted.length
      });

      return decrypted.toString('utf8');
    } catch (error) {
      this.logger.error('Decryption failed - possible tampering', {
        keyVersion,
        error: error.message
      });
      throw new Error('Decryption failed: authentication error');
    }
  }

  // Streaming encryption for large files
  createEncryptStream(associatedData = '') {
    if (!this.currentKeyVersion) {
      throw new Error('No encryption key configured');
    }

    const keyData = this.keyStore.get(this.currentKeyVersion);
    const iv = crypto.randomBytes(this.ivLength);
    const cipher = crypto.createCipheriv(this.algorithm, keyData.key, iv, {
      authTagLength: this.tagLength
    });

    if (associatedData) {
      cipher.setAAD(Buffer.from(associatedData, 'utf8'));
    }

    let headerWritten = false;
    const keyVersion = this.currentKeyVersion;
    const ivLength = this.ivLength;

    const transform = new Transform({
      transform(chunk, encoding, callback) {
        try {
          if (!headerWritten) {
            // Write header: version + IV
            const versionBuffer = Buffer.alloc(4);
            versionBuffer.writeUInt32BE(keyVersion);
            this.push(versionBuffer);
            this.push(iv);
            headerWritten = true;
          }
          const encrypted = cipher.update(chunk);
          callback(null, encrypted);
        } catch (err) {
          callback(err);
        }
      },
      flush(callback) {
        try {
          const final = cipher.final();
          const authTag = cipher.getAuthTag();
          // Append auth tag at the end
          this.push(final);
          this.push(authTag);
          callback();
        } catch (err) {
          callback(err);
        }
      }
    });

    return transform;
  }

  // Encrypt file with streaming
  async encryptFile(inputPath, outputPath, associatedData = '') {
    const encryptStream = this.createEncryptStream(associatedData);

    await pipeline(
      fs.createReadStream(inputPath),
      encryptStream,
      fs.createWriteStream(outputPath)
    );

    this.logger.info('File encrypted', {
      input: inputPath,
      output: outputPath,
      keyVersion: this.currentKeyVersion
    });
  }

  // Re-encrypt data with new key (for key rotation)
  async reencrypt(encryptedBase64, associatedData = '') {
    const plaintext = this.decrypt(encryptedBase64, associatedData);
    return this.encrypt(plaintext, associatedData);
  }

  // Secure key generation helper
  static generateKey() {
    return crypto.randomBytes(32);
  }

  // Key derivation from password (for user-based encryption)
  static async deriveKeyFromPassword(password, salt) {
    return new Promise((resolve, reject) => {
      crypto.scrypt(password, salt, 32, { N: 16384, r: 8, p: 1 }, (err, key) => {
        if (err) reject(err);
        else resolve(key);
      });
    });
  }
}

