Your question touches on a critical cryptographic vulnerability. ECB (Electronic Codebook) mode is fundamentally broken for encrypting data with any patterns or structure, as identical plaintext blocks produce identical ciphertext blocks.

**VULNERABLE CODE**:

```go
package main

import (
	"crypto/aes"
	"encoding/hex"
	"fmt"
	"log"
)

// VULNERABLE: ECB mode encryption
func encryptECB(plaintext []byte, key []byte) ([]byte, error) {
	block, err := aes.NewCipher(key)
	if err != nil {
		return nil, err
	}

	blockSize := block.BlockSize()

	// Pad plaintext to block size
	padding := blockSize - (len(plaintext) % blockSize)
	for i := 0; i < padding; i++ {
		plaintext = append(plaintext, byte(padding))
	}

	ciphertext := make([]byte, len(plaintext))

	// VULNERABLE: ECB encrypts each block independently
	for i := 0; i < len(plaintext); i += blockSize {
		block.Encrypt(ciphertext[i:i+blockSize], plaintext[i:i+blockSize])
	}

	return ciphertext, nil
}

func main() {
	key := []byte("0123456789abcdef") // 16-byte key for AES-128

	// Same data repeated shows pattern leakage
	secretData := []byte("passwordpasswordpasswordpassword")

	encrypted, err := encryptECB(secretData, key)
	if err != nil {
		log.Fatal(err)
	}

	fmt.Printf("Ciphertext: %s\n", hex.EncodeToString(encrypted))
	// Notice: repeated 16-byte blocks produce identical ciphertext!
}
```

**Attack Demonstration**:
