Excellent question! Large file encryption and streaming require careful consideration of memory usage, nonce management, and chunk authentication. Here's a production-ready approach:

**PRODUCTION PATTERN**:

```go
package crypto

import (
	"crypto/aes"
	"crypto/cipher"
	"crypto/rand"
	"crypto/sha256"
	"encoding/binary"
	"errors"
	"fmt"
	"io"
	"log/slog"
	"os"

	"golang.org/x/crypto/hkdf"
)

const (
	// ChunkSize for streaming encryption (64KB chunks)
	ChunkSize = 64 * 1024
	// KeySize for AES-256
	KeySize = 32
	// SaltSize for key derivation
	SaltSize = 32
	// FileHeaderSize contains version, salt, and file nonce
	FileHeaderSize = 1 + SaltSize + 12
)

// FileEncryptor handles secure large file encryption
type FileEncryptor struct {
	logger *slog.Logger
}

// NewFileEncryptor creates a production file encryptor
func NewFileEncryptor(logger *slog.Logger) *FileEncryptor {
	return &FileEncryptor{logger: logger}
}

// deriveKey uses HKDF to derive encryption key from master key
func deriveKey(masterKey, salt []byte, info string) ([]byte, error) {
	hkdfReader := hkdf.New(sha256.New, masterKey, salt, []byte(info))
	key := make([]byte, KeySize)
	if _, err := io.ReadFull(hkdfReader, key); err != nil {
		return nil, fmt.Errorf("key derivation failed: %w", err)
	}
	return key, nil
}

// EncryptFile encrypts a file using streaming AEAD with per-chunk authentication
func (fe *FileEncryptor) EncryptFile(inputPath, outputPath string, masterKey []byte) error {
	if len(masterKey) != KeySize {
		return errors.New("invalid master key size")
	}

	inFile, err := os.Open(inputPath)
	if err != nil {
		return fmt.Errorf("failed to open input file: %w", err)
	}
	defer inFile.Close()

	outFile, err := os.OpenFile(outputPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0600)
	if err != nil {
		return fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Generate random salt for key derivation
	salt := make([]byte, SaltSize)
	if _, err := rand.Read(salt); err != nil {
		return fmt.Errorf("failed to generate salt: %w", err)
	}

	// Derive unique encryption key
	encKey, err := deriveKey(masterKey, salt, "file-encryption-v1")
	if err != nil {
		return err
	}
	defer clearBytes(encKey) // Clear sensitive data

	// Initialize AES-GCM
	block, err := aes.NewCipher(encKey)
	if err != nil {
		return fmt.Errorf("failed to create cipher: %w", err)
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return fmt.Errorf("failed to create GCM: %w", err)
	}

	// Generate base nonce (will be incremented per chunk)
	baseNonce := make([]byte, aesGCM.NonceSize())
	if _, err := rand.Read(baseNonce); err != nil {
		return fmt.Errorf("failed to generate nonce: %w", err)
	}

	// Write file header: version (1) + salt (32) + base nonce (12)
	header := make([]byte, 0, FileHeaderSize)
	header = append(header, 0x01) // Version 1
	header = append(header, salt...)
	header = append(header, baseNonce...)

	if _, err := outFile.Write(header); err != nil {
		return fmt.Errorf("failed to write header: %w", err)
	}

	// Encrypt file in chunks
	buffer := make([]byte, ChunkSize)
	chunkNum := uint64(0)

	for {
		n, err := inFile.Read(buffer)
		if err != nil && err != io.EOF {
			return fmt.Errorf("failed to read chunk: %w", err)
		}
		if n == 0 {
			break
		}

		// Create unique nonce for this chunk (base nonce XOR chunk number)
		chunkNonce := make([]byte, len(baseNonce))
		copy(chunkNonce, baseNonce)
		binary.BigEndian.PutUint64(chunkNonce[4:], chunkNum)

		// Additional authenticated data includes chunk number for ordering
		aad := make([]byte, 8)
		binary.BigEndian.PutUint64(aad, chunkNum)

		// Encrypt chunk with authentication
		ciphertext := aesGCM.Seal(nil, chunkNonce, buffer[:n], aad)

		// Write chunk length and ciphertext
		lengthBuf := make([]byte, 4)
		binary.BigEndian.PutUint32(lengthBuf, uint32(len(ciphertext)))

		if _, err := outFile.Write(lengthBuf); err != nil {
			return fmt.Errorf("failed to write chunk length: %w", err)
		}
		if _, err := outFile.Write(ciphertext); err != nil {
			return fmt.Errorf("failed to write chunk: %w", err)
		}

		chunkNum++

		// Prevent nonce overflow
		if chunkNum > 1<<32 {
			return errors.New("file too large: nonce space exhausted")
		}
	}

	fe.logger.Info("file encrypted successfully",
		"input", inputPath,
		"output", outputPath,
		"chunks", chunkNum,
	)

	return nil
}

// DecryptFile decrypts a file with full integrity verification
func (fe *FileEncryptor) DecryptFile(inputPath, outputPath string, masterKey []byte) error {
	if len(masterKey) != KeySize {
		return errors.New("invalid master key size")
	}

	inFile, err := os.Open(inputPath)
	if err != nil {
		return fmt.Errorf("failed to open input file: %w", err)
	}
	defer inFile.Close()

	// Read and parse header
	header := make([]byte, FileHeaderSize)
	if _, err := io.ReadFull(inFile, header); err != nil {
		return fmt.Errorf("failed to read header: %w", err)
	}

	version := header[0]
	if version != 0x01 {
		return fmt.Errorf("unsupported file version: %d", version)
	}

	salt := header[1 : 1+SaltSize]
	baseNonce := header[1+SaltSize:]

	// Derive decryption key
	decKey, err := deriveKey(masterKey, salt, "file-encryption-v1")
	if err != nil {
		return err
	}
	defer clearBytes(decKey)

	// Initialize AES-GCM
	block, err := aes.NewCipher(decKey)
	if err != nil {
		return fmt.Errorf("failed to create cipher: %w", err)
	}

	aesGCM, err := cipher.NewGCM(block)
	if err != nil {
		return fmt.Errorf("failed to create GCM: %w", err)
	}

	// Create output file with restrictive permissions
	outFile, err := os.OpenFile(outputPath, os.O_WRONLY|os.O_CREATE|os.O_TRUNC, 0600)
	if err != nil {
		return fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Decrypt chunks
	lengthBuf := make([]byte, 4)
	chunkNum := uint64(0)

	for {
		// Read chunk length
		if _, err := io.ReadFull(inFile, lengthBuf); err != nil {
			if err == io.EOF {
				break
			}
			return fmt.Errorf("failed to read chunk length: %w", err)
		}

		chunkLen := binary.BigEndian.Uint32(lengthBuf)
		if chunkLen > ChunkSize+aesGCM.Overhead() {
			return errors.New("invalid chunk size: possible tampering")
		}

		// Read ciphertext
		ciphertext := make([]byte, chunkLen)
		if _, err := io.ReadFull(inFile, ciphertext); err != nil {
			return fmt.Errorf("failed to read chunk: %w", err)
		}

		// Reconstruct chunk nonce
		chunkNonce := make([]byte, len(baseNonce))
		copy(chunkNonce, baseNonce)
		binary.BigEndian.PutUint64(chunkNonce[4:], chunkNum)

		// Reconstruct AAD
		aad := make([]byte, 8)
		binary.BigEndian.PutUint64(aad, chunkNum)

		// Decrypt and verify
		plaintext, err := aesGCM.Open(nil, chunkNonce, ciphertext, aad)
		if err != nil {
			fe.logger.Error("decryption failed: integrity check failed",
				"chunk", chunkNum,
				"file", inputPath,
			)
			return fmt.Errorf("chunk %d: integrity verification failed (tampering detected)", chunkNum)
		}

		if _, err := outFile.Write(plaintext); err != nil {
			return fmt.Errorf("failed to write decrypted chunk: %w", err)
		}

		chunkNum++
	}

	fe.logger.Info("file decrypted successfully",
		"input", inputPath,
		"output", outputPath,
		"chunks", chunkNum,
	)

	return nil
}

// clearBytes securely clears sensitive data from memory
func clearBytes(b []byte) {
	for i := range b {
		b[i] = 0
	}
}
