namespace SecureCrypto
{
    public class SecureUserDataEncryptor
    {
        private readonly byte[] _key;
        private const int IvSize = 16; // 128 bits for AES

        public SecureUserDataEncryptor(byte[] key)
        {
            if (key == null || key.Length != 32) // 256-bit key
                throw new ArgumentException("Key must be 256 bits (32 bytes)");
            _key = key;
        }

        // SECURE: Using AES-GCM (authenticated encryption)
        public byte[] EncryptUserData(string userData)
        {
            byte[] plainBytes = Encoding.UTF8.GetBytes(userData);
            byte[] nonce = new byte[AesGcm.NonceByteSizes.MaxSize]; // 12 bytes
            byte[] tag = new byte[AesGcm.TagByteSizes.MaxSize];     // 16 bytes
            byte[] ciphertext = new byte[plainBytes.Length];

            // Generate cryptographically secure random nonce
            using (RandomNumberGenerator rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(nonce);
            }

            using (AesGcm aesGcm = new AesGcm(_key, AesGcm.TagByteSizes.MaxSize))
            {
                aesGcm.Encrypt(nonce, plainBytes, ciphertext, tag);
            }

            // Combine: nonce || ciphertext || tag
            byte[] result = new byte[nonce.Length + ciphertext.Length + tag.Length];
            Buffer.BlockCopy(nonce, 0, result, 0, nonce.Length);
            Buffer.BlockCopy(ciphertext, 0, result, nonce.Length, ciphertext.Length);
            Buffer.BlockCopy(tag, 0, result, nonce.Length + ciphertext.Length, tag.Length);

            return result;
        }

        public string DecryptUserData(byte[] encryptedData)
        {
            if (encryptedData.Length < AesGcm.NonceByteSizes.MaxSize + AesGcm.TagByteSizes.MaxSize)
                throw new CryptographicException("Invalid ciphertext length");

            int nonceSize = AesGcm.NonceByteSizes.MaxSize;
            int tagSize = AesGcm.TagByteSizes.MaxSize;
            int ciphertextSize = encryptedData.Length - nonceSize - tagSize;

            byte[] nonce = new byte[nonceSize];
            byte[] ciphertext = new byte[ciphertextSize];
            byte[] tag = new byte[tagSize];
            byte[] plaintext = new byte[ciphertextSize];

            Buffer.BlockCopy(encryptedData, 0, nonce, 0, nonceSize);
            Buffer.BlockCopy(encryptedData, nonceSize, ciphertext, 0, ciphertextSize);
            Buffer.BlockCopy(encryptedData, nonceSize + ciphertextSize, tag, 0, tagSize);

            using (AesGcm aesGcm = new AesGcm(_key, tagSize))
            {
                aesGcm.Decrypt(nonce, ciphertext, tag, plaintext);
            }

            return Encoding.UTF8.GetString(plaintext);
        }
    }
}
```

**Key Security Controls**:
- **AES-GCM Mode**: Authenticated encryption providing both confidentiality and integrity
- **Random Nonce**: Unique nonce for each encryption ensures identical plaintexts produce different ciphertexts
- **Authentication Tag**: Detects any tampering with the ciphertext
- **256-bit Key**: Maximum AES key strength for future-proofing

Excellent question! AES-GCM has a limit of approximately 64 GB per nonce (2^39 - 256 bits to maintain security). For large files or streaming data, you need a chunked encryption approach with proper nonce management.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using Microsoft.Extensions.Logging;

namespace SecureCrypto.Production
{
    public sealed class SecureFileEncryptor : IDisposable
    {
        private readonly byte[] _masterKey;
        private readonly ILogger<SecureFileEncryptor> _logger;
        private const int ChunkSize = 64 * 1024; // 64 KB chunks
        private const int NonceSize = 12;
        private const int TagSize = 16;
        private const int KeySize = 32;
        private const int SaltSize = 32;
        private const int HeaderSize = 4; // Version + metadata
        private const byte CurrentVersion = 0x01;
        private bool _disposed;

        public SecureFileEncryptor(byte[] masterKey, ILogger<SecureFileEncryptor> logger)
        {
            if (masterKey == null || masterKey.Length != KeySize)
                throw new ArgumentException($"Master key must be {KeySize} bytes", nameof(masterKey));

            _masterKey = new byte[KeySize];
            Buffer.BlockCopy(masterKey, 0, _masterKey, 0, KeySize);
            _logger = logger ?? throw new ArgumentNullException(nameof(logger));
        }

        /// <summary>
        /// Encrypts a file using chunked AES-GCM with per-file key derivation
        /// </summary>
        public async Task EncryptFileAsync(string inputPath, string outputPath, CancellationToken ct = default)
        {
            ValidateNotDisposed();

            if (!File.Exists(inputPath))
                throw new FileNotFoundException("Input file not found", inputPath);

            _logger.LogInformation("Starting encryption for file: {InputPath}", SanitizeLogPath(inputPath));

            // Generate per-file salt and derive unique file key
            byte[] salt = GenerateSecureRandom(SaltSize);
            byte[] fileKey = DeriveFileKey(_masterKey, salt);

            try
            {
                await using FileStream inputStream = new FileStream(
                    inputPath, FileMode.Open, FileAccess.Read, FileShare.Read, 
                    bufferSize: ChunkSize, useAsync: true);

                await using FileStream outputStream = new FileStream(
                    outputPath, FileMode.Create, FileAccess.Write, FileShare.None,
                    bufferSize: ChunkSize, useAsync: true);

                // Write header: [Version(1)][Salt(32)]
                outputStream.WriteByte(CurrentVersion);
                await outputStream.WriteAsync(salt, ct);

                byte[] buffer = new byte[ChunkSize];
                ulong chunkCounter = 0;
                int bytesRead;

                while ((bytesRead = await inputStream.ReadAsync(buffer.AsMemory(0, ChunkSize), ct)) > 0)
                {
                    ct.ThrowIfCancellationRequested();

                    // Derive unique nonce for each chunk: counter-based
                    byte[] nonce = DeriveChunkNonce(chunkCounter);
                    byte[] chunkData = new byte[bytesRead];
                    Buffer.BlockCopy(buffer, 0, chunkData, 0, bytesRead);

                    byte[] encryptedChunk = EncryptChunk(fileKey, nonce, chunkData, chunkCounter);

                    // Write chunk: [ChunkLength(4)][Nonce(12)][Ciphertext][Tag(16)]
                    byte[] lengthBytes = BitConverter.GetBytes(encryptedChunk.Length);
                    await outputStream.WriteAsync(lengthBytes, ct);
                    await outputStream.WriteAsync(encryptedChunk, ct);

                    chunkCounter++;

                    if (chunkCounter % 1000 == 0)
                        _logger.LogDebug("Encrypted {ChunkCount} chunks", chunkCounter);
                }

                _logger.LogInformation("Encryption complete: {ChunkCount} chunks processed", chunkCounter);
            }
            finally
            {
                CryptographicOperations.ZeroMemory(fileKey);
            }
        }

        /// <summary>
        /// Decrypts a file encrypted with EncryptFileAsync
        /// </summary>
        public async Task DecryptFileAsync(string inputPath, string outputPath, CancellationToken ct = default)
        {
            ValidateNotDisposed();

            if (!File.Exists(inputPath))
                throw new FileNotFoundException("Encrypted file not found", inputPath);

            _logger.LogInformation("Starting decryption for file: {InputPath}", SanitizeLogPath(inputPath));

            await using FileStream inputStream = new FileStream(
                inputPath, FileMode.Open, FileAccess.Read, FileShare.Read,
                bufferSize: ChunkSize, useAsync: true);

            // Read and validate header
            int version = inputStream.ReadByte();
            if (version != CurrentVersion)
                throw new CryptographicException($"Unsupported encryption version: {version}");

            byte[] salt = new byte[SaltSize];
            int saltRead = await inputStream.ReadAsync(salt, ct);
            if (saltRead != SaltSize)
                throw new CryptographicException("Invalid file header: salt truncated");

            byte[] fileKey = DeriveFileKey(_masterKey, salt);

            try
            {
                await using FileStream outputStream = new FileStream(
                    outputPath, FileMode.Create, FileAccess.Write, FileShare.None,
                    bufferSize: ChunkSize, useAsync: true);

                byte[] lengthBuffer = new byte[4];
                ulong chunkCounter = 0;

                while (await inputStream.ReadAsync(lengthBuffer, ct) == 4)
                {
                    ct.ThrowIfCancellationRequested();

                    int chunkLength = BitConverter.ToInt32(lengthBuffer, 0);
                    if (chunkLength <= 0 || chunkLength > ChunkSize + NonceSize + TagSize + 100)
                        throw new CryptographicException("Invalid chunk length detected");

                    byte[] encryptedChunk = new byte[chunkLength];
                    int read = await inputStream.ReadAsync(encryptedChunk, ct);
                    if (read != chunkLength)
                        throw new CryptographicException("Truncated chunk detected");

                    byte[] decryptedChunk = DecryptChunk(fileKey, encryptedChunk, chunkCounter);
                    await outputStream.WriteAsync(decryptedChunk, ct);

                    chunkCounter++;
                }

                _logger.LogInformation("Decryption complete: {ChunkCount} chunks processed", chunkCounter);
            }
            finally
            {
                CryptographicOperations.ZeroMemory(fileKey);
            }
        }

        private byte[] EncryptChunk(byte[] key, byte[] nonce, byte[] plaintext, ulong chunkIndex)
        {
            byte[] ciphertext = new byte[plaintext.Length];
            byte[] tag = new byte[TagSize];

            // Include chunk index in AAD to prevent reordering attacks
            byte[] aad = BitConverter.GetBytes(chunkIndex);

            using (AesGcm aesGcm = new AesGcm(key, TagSize))
            {
                aesGcm.Encrypt(nonce, plaintext, ciphertext, tag, aad);
            }

            // Return: nonce || ciphertext || tag
            byte[] result = new byte[NonceSize + ciphertext.Length + TagSize];
            Buffer.BlockCopy(nonce, 0, result, 0, NonceSize);
            Buffer.BlockCopy(ciphertext, 0, result, NonceSize, ciphertext.Length);
            Buffer.BlockCopy(tag, 0, result, NonceSize + ciphertext.Length, TagSize);

            return result;
        }

        private byte[] DecryptChunk(byte[] key, byte[] encryptedChunk, ulong expectedChunkIndex)
        {
            if (encryptedChunk.Length < NonceSize + TagSize)
                throw new CryptographicException("Invalid encrypted chunk size");

            byte[] nonce = new byte[NonceSize];
            byte[] tag = new byte[TagSize];
            int ciphertextLength = encryptedChunk.Length - NonceSize - TagSize;
            byte[] ciphertext = new byte[ciphertextLength];
            byte[] plaintext = new byte[ciphertextLength];

            Buffer.BlockCopy(encryptedChunk, 0, nonce, 0, NonceSize);
            Buffer.BlockCopy(encryptedChunk, NonceSize, ciphertext, 0, ciphertextLength);
            Buffer.BlockCopy(encryptedChunk, NonceSize + ciphertextLength, tag, 0, TagSize);

            byte[] aad = BitConverter.GetBytes(expectedChunkIndex);

            using (AesGcm aesGcm = new AesGcm(key, TagSize))
            {
                aesGcm.Decrypt(nonce, ciphertext, tag, plaintext, aad);
            }

            return plaintext;
        }

        private static byte[] DeriveFileKey(byte[] masterKey, byte[] salt)
        {
            // HKDF for key derivation (or use Rfc2898DeriveBytes for compatibility)
            using (var hkdf = new HKDF(HashAlgorithmName.SHA256, masterKey, salt, 
                Encoding.UTF8.GetBytes("file-encryption-v1")))
            {
                return hkdf.GetBytes(KeySize);
            }
        }

        private static byte[] DeriveChunkNonce(ulong chunkCounter)
        {
            // Counter-based nonce derivation (safe with random per-file salt)
            byte[] nonce = new byte[NonceSize];
            byte[] counterBytes = BitConverter.GetBytes(chunkCounter);
            Buffer.BlockCopy(counterBytes, 0, nonce, 0, counterBytes.Length);
            return nonce;
        }

        private static byte[] GenerateSecureRandom(int length)
        {
            byte[] buffer = new byte[length];
            using (RandomNumberGenerator rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(buffer);
            }
            return buffer;
        }

        private static string SanitizeLogPath(string path) =>
            Path.GetFileName(path); // Don't log full paths

        private void ValidateNotDisposed()
        {
            if (_disposed)
                throw new ObjectDisposedException(nameof(SecureFileEncryptor));
        }

        public void Dispose()
        {
            if (!_disposed)
            {
                CryptographicOperations.ZeroMemory(_masterKey);
                _disposed = true;
            }
        }
    }

    // Simple HKDF implementation (use Bouncy Castle or .NET 5+ HKDF in production)
    public sealed class HKDF : IDisposable
    {
        private readonly byte[] _prk;
        private readonly byte[] _info;
        private readonly HashAlgorithmName _hashAlgorithm;

        public HKDF(HashAlgorithmName algorithm, byte[] ikm, byte[] salt, byte[] info)
        {
            _hashAlgorithm = algorithm;
            _info = info ?? Array.Empty<byte>();

            // Extract
            using (var hmac = new HMACSHA256(salt ?? new byte[32]))
            {
                _prk = hmac.ComputeHash(ikm);
            }
        }

        public byte[] GetBytes(int outputLength)
        {
            // Expand
            byte[] output = new byte[outputLength];
            byte[] t = Array.Empty<byte>();
            int offset = 0;
            byte counter = 1;

            while (offset < outputLength)
            {
                using (var hmac = new HMACSHA256(_prk))
                {
                    byte[] input = new byte[t.Length + _info.Length + 1];
                    Buffer.BlockCopy(t, 0, input, 0, t.Length);
                    Buffer.BlockCopy(_info, 0, input, t.Length, _info.Length);
                    input[input.Length - 1] = counter;

                    t = hmac.ComputeHash(input);
                }

                int copyLength = Math.Min(t.Length, outputLength - offset);
                Buffer.BlockCopy(t, 0, output, offset, copyLength);
                offset += copyLength;
                counter++;
            }

            return output;
        }

        public void Dispose() => CryptographicOperations.ZeroMemory(_prk);
    }
}
```

**Defense in Depth Layers**:

1. **Per-File Key Derivation**:
```csharp
// Each file gets a unique encryption key derived from master key + random salt
byte[] salt = GenerateSecureRandom(SaltSize);  // Unique per file
byte[] fileKey = DeriveFileKey(_masterKey, salt);  // HKDF derivation
// Compromise of one file's key doesn't expose master key
```

2. **Counter-Based Nonce with AAD**:
```csharp
// Nonce derived from chunk counter (never repeats within file)
byte[] nonce = DeriveChunkNonce(chunkCounter);
// AAD prevents chunk reordering attacks
byte[] aad = BitConverter.GetBytes(chunkIndex);
aesGcm.Encrypt(nonce, plaintext, ciphertext, tag, aad);
```

3. **Secure Memory Handling**:
```csharp
// Always zero sensitive key material when done
try
{
    // ... use fileKey ...
}
finally
{
    CryptographicOperations.ZeroMemory(fileKey);
}
```

**Additional Protections**:

- **Version Header**: Allows future algorithm upgrades without breaking existing files
- **Chunk Length Validation**: Prevents memory exhaustion attacks from malformed files
- **Constant-Time Operations**: `CryptographicOperations.ZeroMemory` avoids timing attacks
- **IDisposable Pattern**: Ensures cryptographic material is cleaned up
- **Async I/O**: Non-blocking for large files, supports cancellation
- **Logging Sanitization**: Never logs full file paths (prevents path traversal info leaks)
- **Fail-Secure**: Any tampering detected by GCM throws `CryptographicException`
